/* ─────────────────────────────────────────────
   SKILL CARD with bars
───────────────────────────────────────────── */
function SkillCard({ s }) {
  const ref = useRef(null);
  const [animate, setAnimate] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setAnimate(true); obs.disconnect(); } }, { threshold: .3 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div className="skill-card" ref={ref}>
      <span className="skill-icon">{s.icon}</span>
      <div className="skill-name">{s.name}</div>
      <div className="skill-tags">{s.tags.map(t => <span className="stag" key={t}>{t}</span>)}</div>
      <div className="skill-bar-wrap">
        {s.bars.map(b => (
          <div key={b.name} style={{marginTop:10}}>
            <div className="skill-bar-label">
              <span className="skill-bar-name">{b.name}</span>
              <span className="skill-bar-pct">{b.pct}%</span>
            </div>
            <div className="skill-bar-track">
              <div className={`skill-bar-fill${animate ? ' animate' : ''}`} style={{'--pct': `${b.pct}%`}} />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────
   COUNTER SECTION
───────────────────────────────────────────── */
function Counters() {
  const ref = useRef(null);
  const [started, setStarted] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setStarted(true); obs.disconnect(); } }, { threshold: .4 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  const years = useCounter(2, 1200, started);
  const projects = useCounter(10, 1500, started);
  const coverage = useCounter(80, 1800, started);
  return (
    <div className="counters fade-in" ref={ref}>
      {[
        { num: years, suffix: "+", label: "Anos de experiência" },
        { num: projects, suffix: "+", label: "Projetos entregues" },
        { num: coverage, suffix: "%", label: "Cobertura de testes" },
      ].map(c => (
        <div className="counter-item" key={c.label}>
          <div className="counter-num">{c.num}<sup>{c.suffix}</sup></div>
          <div className="counter-label">{c.label}</div>
        </div>
      ))}
    </div>
  );
}

/* ─────────────────────────────────────────────
   CONTACT FORM
───────────────────────────────────────────── */
function ContactForm() {
  const [form, setForm] = useState({ nome: "", email: "", assunto: "", mensagem: "" });
  const [status, setStatus] = useState(null); // null | 'sending' | 'ok' | 'err'

  const handle = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const submit = async (e) => {
    e.preventDefault();
    if (!form.nome || !form.email || !form.mensagem) {
      setStatus("err_empty");
      return;
    }
    setStatus("sending");
    try {
      await emailjs.send(
        "service_pzrun8s",
        "template_ae7qy3k",
        {
          nome: form.nome,
          email: form.email,
          assunto: form.assunto,
          mensagem: form.mensagem,
        },
        "uS6X_dbxaOIfcTjUQ"
      );
      setStatus("ok");
      setForm({ nome: "", email: "", assunto: "", mensagem: "" });
    } catch {
      setStatus("err_empty");
    }
  };

  return (
    <form className="contact-form" onSubmit={submit}>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Nome</label>
          <input className="form-input" name="nome" value={form.nome} onChange={handle} placeholder="Seu nome" />
        </div>
        <div className="form-group">
          <label className="form-label">E-mail</label>
          <input className="form-input" name="email" type="email" value={form.email} onChange={handle} placeholder="seu@email.com" />
        </div>
      </div>
      <div className="form-group">
        <label className="form-label">Assunto</label>
        <input className="form-input" name="assunto" value={form.assunto} onChange={handle} placeholder="Oportunidade, projeto, etc." />
      </div>
      <div className="form-group">
        <label className="form-label">Mensagem</label>
        <textarea className="form-textarea" name="mensagem" value={form.mensagem} onChange={handle} placeholder="Escreva sua mensagem..." />
      </div>
      {status === "ok" && <div className="form-success">✓ Mensagem enviada! Responderei em breve.</div>}
      {status === "err_empty" && <div className="form-error">Preencha os campos obrigatórios.</div>}
      <button className="form-submit" type="submit" disabled={status === "sending"}>
        <span>{status === "sending" ? "Enviando..." : "Enviar Mensagem"}</span>
      </button>
    </form>
  );
}

